1	// claim-office.ts
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	
5	type Step = { op: string; items: Item[] };
6	
7	type Customer = { yearsWithMHPCO: number };
8	
9	type Scenario = {
10	  customer: Customer;
11	  steps: Step[];
12	};
13	
14	type StepResult = { premium: number };
15	
16	type ScenarioResult = {
17	  results: StepResult[];
18	};
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const PROCESSING_FEE = 5;
31	
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE_PREMIUM = 60;
34	
35	const CURSE_SURCHARGE_RATE = 0.5;
36	
37	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
39	
40	const LOYALTY_DISCOUNT_RATE = 0.2;
41	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
42	
43	const countItemsByType = (items: Item[]): Map<string, number> => {
44	  const counts = new Map<string, number>();
45	  for (const item of items) {
46	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
47	  }
48	  return counts;
49	};
50	
51	const basePremiumForGroup = (type: string, count: number): number =>
52	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
53	
54	const calculateTotalBasePremium = (items: Item[]): number =>
55	  [...countItemsByType(items)].reduce(
56	    (total, [type, count]) => total + basePremiumForGroup(type, count),
57	    0,
58	  );
59	
60	const curseSurchargeForItem = (item: Item): number =>
61	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
62	
63	const enchantmentSurchargeForItem = (item: Item): number =>
64	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
65	    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
66	    : 0;
67	
68	const sumSurcharges = (
69	  items: Item[],
70	  surchargeForItem: (item: Item) => number,
71	): number =>
72	  items.reduce((total, item) => total + surchargeForItem(item), 0);
73	
74	const quoteStep = (step: Step, customer: Customer): StepResult => {
75	  const totalBasePremium = calculateTotalBasePremium(step.items);
76	  const firstInsuranceSurcharge =
77	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
78	  const curseSurcharge = sumSurcharges(step.items, curseSurchargeForItem);
79	  const enchantmentSurcharge = sumSurcharges(
80	    step.items,
81	    enchantmentSurchargeForItem,
82	  );
83	  const loyaltyDiscount =
84	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
85	      ? totalBasePremium * LOYALTY_DISCOUNT_RATE
86	      : 0;
87	  return {
88	    premium: Math.ceil(
89	      totalBasePremium + curseSurcharge + enchantmentSurcharge +
90	        firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE,
91	    ),
92	  };
93	};
94	
95	export const processScenario = (scenario: Scenario): ScenarioResult => ({
96	  results: scenario.steps.map((step) => quoteStep(step, scenario.customer)),
97	});
